#!/usr/bin/env python3# -*- coding: utf-8 -*-"""Created on Sun Nov  3 13:27:02 2024Read input GTF and extract uORF features for your transcript of interest.@author: bbowles"""import argparseimport pandas as pddef parse_gtf(file_path):    """    Parse a GTF (General Transfer Format) file into a pandas DataFrame.        Args:        file_path (str): Path to the GTF file            Returns:        pandas.DataFrame: DataFrame containing the GTF data with standard columns    """    try:        # GTF has 9 standard columns        columns = [            'seqname', 'source', 'feature', 'start', 'end',            'score', 'strand', 'frame', 'attributes'        ]                # Read the GTF file        df = pd.read_csv(            file_path,            sep='\t',            comment='#',            names=columns,            header=None        )                # Convert numeric columns        df['start'] = pd.to_numeric(df['start'])        df['end'] = pd.to_numeric(df['end'])                # Convert score to numeric, replacing '.' with NaN        df['score'] = pd.to_numeric(df['score'], errors='coerce')                return df            except FileNotFoundError:        print(f"Error: File {file_path} not found")        return None    except Exception as e:        print(f"Error parsing GTF file: {str(e)}")        return Nonedef main():    # Set up argument parser    parser = argparse.ArgumentParser(description='Parse a GTF file into a pandas DataFrame')    parser.add_argument('--gene-id', required=True, help='Ensembl Gene ID.')    parser.add_argument('--gtf', required=True, help='Path to the GTF file.')    parser.add_argument('--fasta', required=True, help='Path to an input FASTA file.')    parser.add_argument('--ensembl-source', required=False, default='ensembl_havana',                        help='Which GTF Data Source (ie Ensembl, Havana) to use.')            # Parse arguments    args = parser.parse_args()    geneid = args.gene_id    source = args.ensembl_source        # Annotate gene_start: the start of coding at the canonical transcript ATG. This is the CDS start position in the Ensembl .gff3.    ensg_df = pd.read_csv(args.gtf,                           header=0,                           sep='\t', comment='#', names=['seqname', 'source', 'feature', 'start', 'end', 'score', 'strand', 'frame', 'attribute'])        # subset to source    ensg_df = ensg_df.loc[ensg_df.source==source]        # Extract gene    ensg_df['gene_id_w_version'] = ensg_df.attribute.str.split(';').str[0].str.split(' ').str[1].str.strip('"')        if '.' not in geneid:        # assume most recent version        ensg_df['gene_id'] = ensg_df.gene_id_w_version.str.split('.').str[0]        ensg_df['id_version'] = ensg_df.gene_id_w_version.str.split('.').str[1].astype(int)                ensg_df = ensg_df.loc[ensg_df.gene_id == geneid]        genid_w_version = f"{geneid}.{str(ensg_df.id_version.max())}"        ensg_df = ensg_df.loc[ensg_df.gene_id_w_version == genid_w_version]             else:        ensg_df = ensg_df.loc[ensg_df.gene_id_w_version == geneid]            if ensg_df.empty:        raise Exception(f'{geneid} not found in source {source}!')            # get CDS start site    CDS_start = ensg_df.loc[ensg_df.feature=='CDS'].start.min()            # subset to source, UTRs    ensg_df = ensg_df.loc[ensg_df.feature=='UTR']        # determine UTR status    def check_identity(region_start, strand, CDS_start):        if strand == '+':            if region_start > CDS_start:                return(3)            elif region_start < CDS_start:                return(5)        if strand == '-':            if region_start > CDS_start:                return(5)            elif region_start < CDS_start:                return(3)    ensg_df['utr_type'] = ensg_df.apply(lambda row: check_identity(row.start, row.strand, CDS_start), axis=1)    ensg_df = ensg_df.loc[ensg_df.utr_type==5]            # unpack transcript    ensg_df['transcript'] = ensg_df.attribute.str.split(';').str[1].str.split(' ').str[2].str.strip('"')    ensg_df['exon'] = ensg_df.attribute.str.split(';').str[6].str.split(' ').str[2]        if __name__ == "__main__":    main()